const text = fs.readFileSync('[EXCLUDED_GENERATED_ARTIFACT]', 'utf8').trim();
const lines = text.split(/\r?\n/);
function parseLine(line) {
  const out = [];
  let cur = '';
  let inQ = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (inQ) {
      if (ch === '"' && line[i + 1] === '"') { cur += '"'; i++; }
      else if (ch === '"') { inQ = false; }
      else { cur += ch; }
    } else {
      if (ch === ',') { out.push(cur); cur = ''; }
      else if (ch === '"') { inQ = true; }
      else { cur += ch; }
    }
  }
  out.push(cur);
  return out;
}
const rows = lines.map(parseLine);
const header = rows[0];
const data = rows.slice(1);
if (data.length !== 3) throw new Error(`Expected 3 data rows, found ${data.length}`);
const idx = Object.fromEntries(header.map((h, i) => [h, i]));
for (const row of data) {
  const run = row[idx.run_id];
  const yieldPct = Number(row[idx.yield_pct]);
  const impurityPct = Number(row[idx.impurity_pct]);
  const yieldPass = row[idx.yield_rule_gt_70] === 'true';
  const impPass = row[idx.impurity_rule_lt_10] === 'true';
  const computedYieldPass = yieldPct > 70;
  const computedImpPass = impurityPct < 10;
  if (yieldPass !== computedYieldPass || impPass !== computedImpPass) {
    throw new Error(`${run} boolean mismatch`);
  }
  const status = row[idx.triage_status];
  if (status !== 'fail') throw new Error(`${run} expected fail, got ${status}`);
}
